export const ansi = {
    white: '\u001b[37m',
    yellow: '\u001b[33m',
    green: '\u001b[32m',
    cyan: '\u001b[36m',
    red: '\u001b[31m',
    bold: '\u001b[1m',
    dim: '\u001b[2m',
    reset: '\u001b[0m',
};
export const ansiRegex = new RegExp(String.fromCharCode(27) + '\\[[0-9;]*m', 'g');
